#include <stdio.h>
#include <stdlib.h>

typedef long long ll;

// Function to calculate the position of the most significant bit in `x`
int significant_bit_position(int x) {
    int pos = 0;
    while (x != 0) {
        x /= 2;
        ++pos;
    }
    return pos;
}

// Main function to solve each test case
void mainSolve() {
    int n;
    scanf("%d", &n);
    ll *v = (ll*)malloc(n * sizeof(ll));

    // Reading input values into the array
    for (int i = 0; i < n; i++) {
        scanf("%lld", &v[i]);
    }

    // Using an array to simulate an unordered_map for bit position frequencies
    ll m[32] = {0}; // Initialize all positions to zero
    for (int i = 0; i < n; i++) {
        int pos = significant_bit_position(v[i]);
        ++m[pos];
    }

    // Calculating the answer
    ll ans = 0;
    for (int i = 0; i < 32; i++) {
        if (m[i] > 1) {
            ans += (m[i] * (m[i] - 1ll)) / 2ll;
        }
    }
    printf("%lld\n", ans);
    free(v); // Free allocated memory
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        mainSolve();
