import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            mainSolve(sc);
        }
        sc.close();
    }

    public static int significantBitPosition(int x) {
        int pos = 0;
        while (x != 0) {
            x /= 2;
            ++pos;
        }
        return pos;
    }

    public static void mainSolve(Scanner sc) {
        int n = sc.nextInt();
        ArrayList<Long> v = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            v.add(sc.nextLong());
        }

        HashMap<Integer, Long> m = new HashMap<>();
        for (long x : v) {
            int pos = significantBitPosition((int) x);
            m.put(pos, m.getOrDefault(pos, 0L) + 1);
        }

        long ans = 0;
        for (Map.Entry<Integer, Long> entry : m.entrySet()) {
            long count = entry.getValue();
            ans += (count * (count - 1)) / 2;
        }

        System.out.println(ans);
    }
}

