const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
rl.on('line', (line) => {
    inputLines.push(line.trim());
});

rl.on('close', () => {
    // Helper function to find the position of the most significant bit
    function significantBitPosition(x) {
        let pos = 0;
        while (x !== 0) {
            x = Math.floor(x / 2);
            pos++;
        }
        return pos;
    }

    let index = 0;
    const T = parseInt(inputLines[index++], 10);

    for (let t = 0; t < T; t++) {
        const n = parseInt(inputLines[index++], 10);
        const v = inputLines[index++].split(' ').map(Number);

        // Map to store frequency of significant bit positions
        const bitPositionMap = new Map();

        for (let x of v) {
            const pos = significantBitPosition(x);
            bitPositionMap.set(pos, (bitPositionMap.get(pos) || 0) + 1);
        }

        let ans = 0;
        for (let count of bitPositionMap.values()) {
            ans += (count * (count - 1)) / 2;
        }

        console.log(ans);
    }
});
